import anthropic, json, asyncio
from dataclasses import dataclass, field

client = anthropic.AsyncAnthropic()

@dataclass
class StreamState:
    """Tracks streaming state across a single LLM call."""
    text_chunks: list[str] = field(default_factory=list)
    active_tool_name: str | None = None
    active_tool_id: str | None = None
    tool_args_buf: str = ""
    pending_tool_calls: list[dict] = field(default_factory=list)

async def run_support_agent(
    conversation: list[dict],
    on_text_chunk,       # callback: (str) -> None, called per token
    on_tool_dispatch,    # callback: (name, args) -> str, returns tool result
) -> str:
    """Run a multi-turn support agent with streaming + early tool dispatch."""
    messages = list(conversation)

    while True:
        state = StreamState()

        async with client.messages.stream(
            model="claude-opus-4-5",
            max_tokens=2048,
            system="You are a helpful customer support agent. Use tools when needed.",
            tools=[{
                "name": "lookup_order",
                "description": "Look up an order by order ID.",
                "input_schema": {
                    "type": "object",
                    "properties": {"order_id": {"type": "string"}},
                    "required": ["order_id"]
                }
            }],
            messages=messages,
        ) as stream:
            async for event in stream:
                if event.type == "content_block_start":
                    block = event.content_block
                    if block.type == "tool_use":
                        state.active_tool_name = block.name
                        state.active_tool_id = block.id
                        state.tool_args_buf = ""

                elif event.type == "content_block_delta":
                    d = event.delta
                    if d.type == "text_delta":
                        on_text_chunk(d.text)  # push to UI immediately
                        state.text_chunks.append(d.text)
                    elif d.type == "input_json_delta":
                        state.tool_args_buf += d.partial_json

                elif event.type == "content_block_stop":
                    if state.active_tool_name:
                        args = json.loads(state.tool_args_buf)
                        # Dispatch EARLY -- tool runs before model finishes generating
                        result = await on_tool_dispatch(state.active_tool_name, args)
                        state.pending_tool_calls.append({
                            "id": state.active_tool_id,
                            "result": result,
                        })
                        state.active_tool_name = None

            final = await stream.get_final_message()

        assistant_content = final.content
        messages.append({"role": "assistant", "content": assistant_content})

        if final.stop_reason != "tool_use":
            return "".join(state.text_chunks)

        # Feed tool results back for the next generation step
        tool_results = [
            {"type": "tool_result", "tool_use_id": tc["id"], "content": tc["result"]}
            for tc in state.pending_tool_calls
        ]
        messages.append({"role": "user", "content": tool_results})

# Usage
async def demo():
    async def tool_handler(name: str, args: dict) -> str:
        if name == "lookup_order":
            return json.dumps({"order_id": args["order_id"], "status": "shipped", "eta": "2026-07-13"})
        return "{}"

    result = await run_support_agent(
        conversation=[{"role": "user", "content": "What is the status of order 12345?"}],
        on_text_chunk=lambda t: print(t, end="", flush=True),
        on_tool_dispatch=tool_handler,
    )
    print(f"\n\nFull response:\n{result}")

asyncio.run(demo())
